import{_ as t,c as a,o,ag as r}from"./chunks/framework.B58IbkZx.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"CampaignBay","text":"The Ultimate Discount Campaign Manager for WooCommerce.","tagline":"Create powerful, automated, and targeted discount campaigns to drive sales and engage your customers.","image":{"src":"/dashboard-overview.png","alt":"CampaignBay Dashboard"},"actions":[{"theme":"brand","text":"Get Started","link":"/installation"},{"theme":"alt","text":"Buy Pro","link":"https://wpanchorbay.com/campaignbay"},{"theme":"alt","text":"Free Download","link":"https://wordpress.org/plugins/campaignbay/"}]}},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":1767077073000}'),i={name:"index.md"};function s(n,e,l,c,g,u){return o(),a("div",null,e[0]||(e[0]=[r('<h2 id="what-is-campaignbay" tabindex="-1">What is CampaignBay? <a class="header-anchor" href="#what-is-campaignbay" aria-label="Permalink to &quot;What is CampaignBay?&quot;">​</a></h2><p>Welcome to the official documentation for CampaignBay!</p><p>CampaignBay is a powerful, user-friendly marketing tool that empowers you to create sophisticated, automated discount campaigns directly from your WordPress dashboard. Whether you&#39;re running a Black Friday flash sale, rewarding customers for bulk purchases, or creating urgency with a limited-time offer, CampaignBay provides the robust features you need to drive sales and engage customers.</p><p>With its intuitive dashboard, flexible campaign types, and high-performance discount engine, you get unparalleled control over your marketing strategy without sacrificing site speed.</p><p>This documentation will guide you through every feature, from installing the plugin to understanding the advanced settings.</p><h2 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to &quot;Key Features&quot;">​</a></h2><p><strong>Campaign Types:</strong></p><ul><li><strong>Scheduled Discounts:</strong> Run time-limited sales with automatic start and end dates. Perfect for holiday sales or weekly specials.</li><li><strong>Quantity Based Discounts:</strong> Tiered pricing like &quot;Buy 3+, get 10% off; Buy 5+, get 20% off.&quot; Customers see a pricing table on the product page.</li><li><strong>Early Bird Discounts:</strong> Reward the first X customers with special pricing. A live counter shows remaining slots.</li><li><strong>BOGO (Buy One Get One):</strong> Classic &quot;Buy 2, Get 1 Free&quot; or &quot;Buy 1, Get 1 at 50% Off&quot; deals. Free items are added directly to the cart.</li></ul><p><strong>Targeting &amp; Conditions:</strong></p><ul><li><strong>Flexible Targeting:</strong> Apply discounts to your entire store, specific products, or categories.</li><li><strong>Product &amp; Category Exclusions:</strong> Fine-tune which items are excluded from discounts.</li><li><strong>User Role Conditions:</strong> Restrict campaigns to Wholesalers, VIPs, or any WordPress role.</li><li><strong>Smart Stacking Logic:</strong> Control how discounts interact with each other and native WooCommerce coupons.</li><li><strong>Coupon Compatibility:</strong> Works seamlessly with WooCommerce coupons (configurable stacking).</li></ul><p><strong>Display &amp; Messaging:</strong></p><ul><li><strong>Customizable Messages:</strong> Dynamic placeholders like <code>{percentage_off}</code>, <code>{buy_quantity}</code> for promotional text.</li><li><strong>Product Page Display:</strong> Discount tables and banners automatically appear on product pages.</li><li><strong>Cart Integration:</strong> Automatic discounts with strikethrough pricing in the cart.</li><li><strong>Campaign Templates:</strong> Pre-built templates for quick campaign setup.</li></ul><p><strong>Analytics Dashboard:</strong></p><ul><li><strong>KPI Cards:</strong> Active Campaigns, Total Discount Value, Discounted Orders, Sales from Campaigns.</li><li><strong>Interactive Charts:</strong> Line, bar, and pie chart visualizations for discount trends.</li><li><strong>Top Performing Campaigns:</strong> Identify your best campaigns at a glance.</li><li><strong>Recent Activity Log:</strong> Track campaign creation and updates.</li><li><strong>Live &amp; Upcoming Campaigns:</strong> Quick view of active and scheduled promotions.</li></ul><p><strong>Performance &amp; Automation:</strong></p><ul><li><strong>Full Scheduling &amp; Automation:</strong> Reliable WP-Cron based activation/deactivation with failsafe mechanisms.</li><li><strong>Performance Optimized:</strong> Multi-level caching keeps your storefront blazingly fast.</li><li><strong>100% Free Core Features:</strong> No artificial limits. Create unlimited campaigns.</li></ul><h2 id="pro-features" tabindex="-1">Pro Features <a class="header-anchor" href="#pro-features" aria-label="Permalink to &quot;Pro Features&quot;">​</a></h2><p>Unlock advanced capabilities with <a href="https://wpanchorbay.com/campaignbay" target="_blank" rel="noreferrer"><strong>CampaignBayPro</strong></a>:</p><ul><li><strong>BOGO Advanced (Buy X Get Y):</strong> Create cross-sell offers like &quot;Buy a Laptop, Get a Mouse Free&quot; with separate Buy and Get product sets.</li><li><strong>Product In Cart Discounts:</strong> Trigger discounts when specific products are in the cart – perfect for accessory upsells.</li><li><strong>Advanced Conditions:</strong> Target by Cart Total, Order History, Specific Products in Cart, and more.</li><li><strong>Priority Email Support:</strong> Get direct access to our development team.</li></ul><p><a href="https://wpanchorbay.com/campaignbay" target="_blank" rel="noreferrer"><strong>Get CampaignBayPro →</strong></a></p><h2 id="live-demo" tabindex="-1">Live Demo <a class="header-anchor" href="#live-demo" aria-label="Permalink to &quot;Live Demo&quot;">​</a></h2><p>Experience the power of CampaignBay firsthand on our interactive demo site. See how campaigns look on the frontend and explore the admin dashboard.</p><ul><li><a href="https://wpanchorbay.com/campaignbay/#demo" target="_blank" rel="noreferrer"><strong>View the Demo (Frontend &amp; Backend)</strong></a></li></ul><h2 id="use-cases" tabindex="-1">Use Cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use Cases&quot;">​</a></h2><p>CampaignBay is designed to help you achieve specific business goals. Here are just a few examples of what you can build:</p><ul><li><p><strong>Launch New Products with a Bang:</strong> Create an <strong>Early Bird Discount</strong> offering a steep discount to the first 50 customers to generate instant buzz and social proof.</p></li><li><p><strong>Increase Average Order Value (AOV):</strong> Implement a tiered <strong>Quantity Discount</strong> like &quot;Buy 3+, get 10% off; Buy 5+, get 20% off&quot; and use the built-in cart notices to encourage customers to add more to their cart.</p></li><li><p><strong>Run Holiday Flash Sales:</strong> Set up a <strong>Scheduled Discount</strong> for your entire store that automatically starts at midnight on Black Friday and ends precisely on Cyber Monday.</p></li><li><p><strong>Clear Out Old Inventory:</strong> Run a &quot;Buy 2, Get 1 Free&quot; <strong>BOGO Campaign</strong> on last season&#39;s styles to quickly move stock without devaluing your brand.</p></li><li><p><strong>Create Simple Wholesale Tiers:</strong> Use <strong>Quantity Discounts</strong> on specific product categories to offer wholesale-style pricing to all your customers without needing a separate plugin.</p></li><li><p><strong>Targeted Promotions:</strong> Apply a discount to a specific product category to promote a new line or run a brand-specific sale.</p></li><li><p><strong>Cross-Sell Bundles (Pro):</strong> With <a href="https://wpanchorbay.com/campaignbay" target="_blank" rel="noreferrer">CampaignBayPro</a>, trigger discounts on accessories when customers add specific products to their cart.</p></li></ul><h2 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h2><p>Ready to dive in? Here are the most important sections to get you started on your journey.</p><div class="vp-doc"><div class="vp-card-group"><div class="vp-card"><a href="./installation"><h3>1. Installation</h3><p>A step-by-step guide to installing and activating the plugin on your WordPress site.</p></a></div><div class="vp-card"><a href="./campaigns/scheduled-discounts"><h3>2. Creating Your First Campaign</h3><p>Learn the basics by creating a simple, time-based scheduled discount.</p></a></div><div class="vp-card"><a href="./settings"><h3>3. Configuring Settings</h3><p>Explore the global settings to tailor the plugin&#39;s behavior to your store&#39;s strategy.</p></a></div></div></div>',29)]))}const m=t(i,[["render",s]]);export{p as __pageData,m as default};
